  ipcMain.handle('skills:list', async () => {
    try {
      const homeDir = process.env.HOME ?? process.env.USERPROFILE ?? ''
      const skillsDirs = [
        { dir: join(homeDir, '.pi', 'agent', 'skills'), scope: 'global' },
        { dir: join(homeDir, '.agents', 'skills'), scope: 'global' },
        { dir: join(process.cwd(), '.pi', 'skills'), scope: 'project' },
        { dir: join(process.cwd(), '.agents', 'skills'), scope: 'project' },
      ]
      const skills: Array<{ name: string; description: string; source: string; scope: string }> = []
      for (const { dir, scope } of skillsDirs) {
        if (!existsSync(dir)) continue
        const entries = readdirSync(dir, { withFileTypes: true })
        for (const entry of entries) {
          if (entry.name.startsWith('.')) continue
          const fullPath = join(dir, entry.name)
          let skillFile = ''
          if (entry.isDirectory()) {
            const candidate = join(fullPath, 'SKILL.md')
            if (existsSync(candidate)) skillFile = candidate
          } else if (entry.name === 'SKILL.md') {
            skillFile = fullPath
          }
          if (!skillFile) continue
          try {
            const content = readFileSync(skillFile, 'utf-8')
            const fmMatch = content.match(/^---\s*\n([\s\S]*?)\n---/)
            const name = entry.isDirectory() ? entry.name : 'skill'
            let description = ''
            if (fmMatch) {
              const frontmatter = fmMatch[1]
              const nameMatch = frontmatter.match(/^name:\s*(.+)$/m)
              const descMatch = frontmatter.match(/^description:\s*(.+)$/m)
              if (nameMatch) skills.push({ name: nameMatch[1].trim(), description: descMatch?.[1]?.trim() ?? '', source: dirname(fullPath), scope })
              else skills.push({ name, description: descMatch?.[1]?.trim() ?? '', source: dirname(fullPath), scope })
            } else {
              skills.push({ name, description: '', source: dirname(fullPath), scope })
            }
          } catch {}
        }
      }
      const seen = new Set<string>()
      return { ok: true, data: skills.filter(s => { if (seen.has(s.name)) return false; seen.add(s.name); return true }) }
    } catch (err: unknown) {
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('mcp:list', async () => {
    try {
      const homeDir = process.env.HOME ?? process.env.USERPROFILE ?? ''
      const configPaths = [
        join(homeDir, '.pi', 'agent', 'settings.json'),
        join(process.cwd(), '.pi', 'settings.json'),
      ]
      const servers: Array<{ name: string; command: string; args?: string[]; env?: Record<string, string> }> = []
      const seenMcp = new Set<string>()
      for (const configPath of configPaths) {
        if (!existsSync(configPath)) continue
        try {
          const content = readFileSync(configPath, 'utf-8')
          const config = JSON.parse(content)
          const mcpServers = config.mcpServers ?? config.mcp_servers ?? {}
          if (typeof mcpServers !== 'object') continue
          for (const [name, serverConfig] of Object.entries(mcpServers)) {
            const sc = serverConfig as Record<string, unknown>
            if (seenMcp.has(name)) continue
            seenMcp.add(name)
            servers.push({
              name,
              command: typeof sc.command === 'string' ? sc.command : '',
              args: Array.isArray(sc.args) ? sc.args.map(String) : undefined,
              env: typeof sc.env === 'object' && sc.env !== null ? Object.fromEntries(Object.entries(sc.env as Record<string, unknown>).map(([k, v]) => [k, String(v)])) : undefined,
            })
          }
        } catch {}
      }
      return { ok: true, data: servers }
    } catch (err: unknown) {
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('mcp:ping', async (_event, serverConfig: { command: string; args?: string[]; env?: Record<string, string> }) => {
    return new Promise<{ ok: boolean; connected: boolean }>((resolve) => {
      const timeout = setTimeout(() => {
        child.kill()
        resolve({ ok: true, connected: false })
      }, 3000)
      try {
        const { spawn } = require('child_process') as typeof import('child_process')
        const child = spawn(serverConfig.command, serverConfig.args ?? [], {
          env: { ...process.env, ...serverConfig.env } as Record<string, string>,
          stdio: ['pipe', 'pipe', 'pipe'],
        })
        const initMsg = JSON.stringify({
          jsonrpc: '2.0',
          id: 1,
          method: 'initialize',
          params: {
            protocolVersion: '2024-11-05',
            capabilities: {},
            clientInfo: { name: 'xi', version: '0.1.0' },
          },
        }) + '\n'
        child.stdin.write(initMsg)
        let buffer = ''
        child.stdout.on('data', (data: Buffer) => {
          buffer += data.toString()
          try {
            JSON.parse(buffer.trim())
            clearTimeout(timeout)
            child.kill()
            resolve({ ok: true, connected: true })
          } catch {}
        })
        child.on('error', () => {
          clearTimeout(timeout)
          resolve({ ok: true, connected: false })
        })
        child.on('exit', () => {
          clearTimeout(timeout)
          resolve({ ok: true, connected: false })
        })
      } catch {
        clearTimeout(timeout)
        resolve({ ok: true, connected: false })
      }
    })
  })
}

