import { utilityProcess } from 'electron'
import workerPath from './pi-worker?modulePath'
import { resolve, join } from 'path'
import { existsSync, mkdirSync, symlinkSync, lstatSync } from 'fs'
import { randomUUID } from 'crypto'
import { EventEmitter } from 'events'

const LINKED_FILES = ['auth.json', 'models.json', 'settings.json']
const LINKED_DIRS = ['tools', 'prompts', 'themes', 'extensions']

interface PendingCommand {
  resolve: (value: unknown) => void
  reject: (reason: Error) => void
  timer: ReturnType<typeof setTimeout>
}

const COMMAND_TIMEOUT_MS = 60_000

interface UtilityChild {
  on(event: 'message', listener: (msg: Record<string, unknown>) => void): UtilityChild
  on(event: 'exit', listener: (code: number | null) => void): UtilityChild
  postMessage(message: unknown): void
  kill(): void
  pid: number | undefined
}

export class PiSDKBridge extends EventEmitter {
  private child: UtilityChild | null = null
  private pendingCommands = new Map<string, PendingCommand>()
  private _isConnected = false
  private _sessionFilePath: string | null = null

  get isConnected(): boolean {
    return this._isConnected && this.child !== null
  }

  get sessionFilePath(): string | null {
    return this._sessionFilePath
  }

  async start(cwd: string, sessionPath?: string): Promise<void> {
    if (this._isConnected) {
      return
    }

    if (this.child) {
      if (this._isConnected) return
      await new Promise<void>((resolve, reject) => {
        const timeout = setTimeout(() => {
          reject(new Error('Timed out waiting for existing process to connect'))
        }, 30_000)
        this.once('connected', () => { clearTimeout(timeout); resolve() })
        this.once('error', (err: Error) => { clearTimeout(timeout); reject(err) })
      })
      return
    }

    const resolvedCwd = resolve(cwd)
    const localAgentDir = join(resolvedCwd, '.xi')
    if (!existsSync(localAgentDir)) {
      mkdirSync(localAgentDir, { recursive: true })
    }
    process.env.PI_CODING_AGENT_DIR = localAgentDir
    this.linkGlobalAgentConfig(localAgentDir)

    const child = utilityProcess.fork(workerPath, [], {
      serviceName: 'pi-sdk',
      stdio: 'pipe',
      env: { ...process.env },
    }) as unknown as UtilityChild

    this.child = child

    child.on('message', (msg: Record<string, unknown>) => {
      this.handleChildMessage(msg)
    })

    child.on('exit', (code: number | null) => {
      console.error('[PiSDKBridge] Process exited with code:', code)
      this._isConnected = false
      this.child = null
      this.rejectAllPending(`Process exited with code ${code}`)
      this.emit('disconnected')
    })

    child.postMessage({ type: 'init', data: { cwd, sessionPath } })

    await new Promise<void>((resolve, reject) => {
      const timeout = setTimeout(() => {
        reject(new Error('Pi SDK process did not respond within 30s'))
      }, 30_000)

      const onConnected = (): void => {
        clearTimeout(timeout)
        resolve()
      }

      const onError = (err: Error): void => {
        clearTimeout(timeout)
        reject(err)
      }

      this.once('connected', onConnected)
      this.once('error', onError)
    })
  }

  sendCommand(command: Record<string, unknown>): void {
    if (!this.child) {
      this.emit('error', new Error('Process not running'))
      return
    }
    this.child.postMessage(command)
  }

  async sendRpcCommand(command: Record<string, unknown>): Promise<unknown> {
    return new Promise((resolve, reject) => {
      if (!this.child) {
        reject(new Error('Process not running'))
        return
      }

      const id = randomUUID()
      const timer = setTimeout(() => {
        this.pendingCommands.delete(id)
        reject(new Error(`SDK command timed out: ${command.type}`))
      }, COMMAND_TIMEOUT_MS)

      this.pendingCommands.set(id, { resolve, reject, timer })
      this.child.postMessage({ ...command, id })
    })
  }

  sendExtensionUIResponse(response: Record<string, unknown>): void {
    this.sendCommand(response)
  }

  async stop(): Promise<void> {
    if (!this.child) return

    this.rejectAllPending('Process stopping')

    this.child.kill()
    this.child = null
    this._isConnected = false
  }

  private linkGlobalAgentConfig(localAgentDir: string): void {
    const globalAgentDir = join(
      process.env.HOME ?? process.env.USERPROFILE ?? '~',
      '.pi',
      'agent'
    )

    for (const file of LINKED_FILES) {
      const source = join(globalAgentDir, file)
      const target = join(localAgentDir, file)
      if (existsSync(source) && !existsSync(target)) {
        try { symlinkSync(source, target) } catch {}
      }
    }

    for (const dir of LINKED_DIRS) {
      const source = join(globalAgentDir, dir)
      const target = join(localAgentDir, dir)
      if (existsSync(source) && !lstatSync(source).isSymbolicLink() && !existsSync(target)) {
        try { symlinkSync(source, target) } catch {}
      }
    }
  }

  private handleChildMessage(msg: Record<string, unknown>): void {
    const channel = msg.channel as string

    switch (channel) {
      case 'connected': {
        this._isConnected = true
        const data = msg.data as Record<string, unknown> | undefined
        if (data?.sessionFile && typeof data.sessionFile === 'string') {
          this._sessionFilePath = data.sessionFile
        }
        this.emit('connected')
        break
      }

      case 'event': {
        this.emit('event', msg.data)
        break
      }

      case 'response': {
        const id = msg.id as string | undefined
        if (id) {
          const pending = this.pendingCommands.get(id)
          if (pending) {
            clearTimeout(pending.timer)
            this.pendingCommands.delete(id)
            if (msg.success) {
              pending.resolve(msg.data)
            } else {
              pending.reject(new Error(typeof msg.error === 'string' ? msg.error : 'SDK command failed'))
            }
          }
        }
        this.emit('response', msg)
        break
      }

      case 'error': {
        this.emit('error', new Error(typeof msg.error === 'string' ? msg.error : 'Unknown worker error'))
        break
      }

      case 'agent_end': {
        break
      }

      default:
        this.emit('event', msg)
    }
  }

  private rejectAllPending(reason: string): void {
    for (const [, pending] of this.pendingCommands) {
      clearTimeout(pending.timer)
      pending.reject(new Error(reason))
    }
    this.pendingCommands.clear()
  }
}

import type { AgentSession, AgentSessionEvent, AgentSessionRuntime } from '@earendil-works/pi-coding-agent'

process.on('uncaughtException', (err: Error) => {
  process.parentPort?.postMessage({ channel: 'error', error: `Uncaught: ${err.message}` })
})

process.on('unhandledRejection', (reason: unknown) => {
  const msg = reason instanceof Error ? reason.message : String(reason)
  process.parentPort?.postMessage({ channel: 'error', error: `Unhandled rejection: ${msg}` })
})

interface WorkerInit {
  cwd: string
  sessionPath?: string
}

interface WorkerCommand {
  id?: string
  type: string
  [key: string]: unknown
}

let session: AgentSession | null = null
let runtime: AgentSessionRuntime | null = null
let sessionManager: import('@earendil-works/pi-coding-agent').SessionManager | null = null
let unsubscribe: (() => void) | null = null
let pi: typeof import('@earendil-works/pi-coding-agent') | null = null

function send(msg: Record<string, unknown>): void {
  process.parentPort?.postMessage(msg)
}

function forwardEvent(event: AgentSessionEvent): void {
  send({ channel: 'event', data: event })
}

async function bindSession(): Promise<void> {
  unsubscribe?.()
  if (!session) return

  await session.bindExtensions({})

  unsubscribe = session.subscribe((event) => {
    forwardEvent(event)

    if (event.type === 'agent_end') {
      send({ channel: 'agent_end' })
    }
  })
}

async function init(data: WorkerInit): Promise<void> {
  pi = await import('@earendil-works/pi-coding-agent')
  const agentDir = pi.getAgentDir()

  const createRuntime: pi.CreateAgentSessionRuntimeFactory = async ({ cwd, sessionManager: sm, sessionStartEvent }) => {
    sessionManager = sm
    const services = await pi!.createAgentSessionServices({ cwd, agentDir })
    return {
      ...(await pi!.createAgentSessionFromServices({
        services,
        sessionManager: sm,
        sessionStartEvent,
      })),
      services,
      diagnostics: services.diagnostics,
    }
  }

  let sm: pi.SessionManager
  if (data.sessionPath) {
    sm = pi.SessionManager.open(data.sessionPath)
  } else {
    sm = pi.SessionManager.continueRecent(data.cwd)
  }

  runtime = await pi.createAgentSessionRuntime(createRuntime, {
    cwd: data.cwd,
    agentDir,
    sessionManager: sm,
  })

  session = runtime.session
  await bindSession()

  send({ channel: 'connected', data: { sessionFile: session.sessionFile, sessionId: session.sessionId } })
}

async function handleCommand(cmd: WorkerCommand): Promise<void> {
  if (!session || !runtime || !pi) {
    send({ channel: 'response', id: cmd.id, success: false, error: 'Session not initialized' })
    return
  }

  try {
    switch (cmd.type) {
      case 'prompt': {
        await session.prompt(cmd.message as string, {
          images: cmd.images as pi.ImageContent[] | undefined,
          streamingBehavior: cmd.streamingBehavior as 'steer' | 'followUp' | undefined,
        })
        send({ channel: 'response', id: cmd.id, command: 'prompt', success: true })
        break
      }

      case 'steer': {
        await session.steer(cmd.message as string, cmd.images as pi.ImageContent[] | undefined)
        send({ channel: 'response', id: cmd.id, command: 'steer', success: true })
        break
      }

      case 'follow_up': {
        await session.followUp(cmd.message as string, cmd.images as pi.ImageContent[] | undefined)
        send({ channel: 'response', id: cmd.id, command: 'follow_up', success: true })
        break
      }

      case 'abort': {
        await session.abort()
        send({ channel: 'response', id: cmd.id, command: 'abort', success: true })
        break
      }

      case 'get_state': {
        const currentModel = session.model
        send({
          channel: 'response',
          id: cmd.id,
          command: 'get_state',
          success: true,
          data: {
            sessionFile: session.sessionFile,
            sessionId: session.sessionId,
            sessionName: session.sessionName,
            isStreaming: session.isStreaming,
            isCompacting: session.isCompacting,
            thinkingLevel: session.thinkingLevel,
            messageCount: session.messages.length,
            model: currentModel
              ? { provider: currentModel.provider, id: currentModel.id, name: currentModel.name }
              : null,
          },
        })
        break
      }

      case 'get_messages': {
        let messages = session.messages
        if (messages.length === 0 && sessionManager) {
          try {
            const entries = sessionManager.getEntries()
            const messageEntries = entries.filter((e) => e.type === 'message' && (e as Record<string, unknown>).message)
            messages = messageEntries.map((e) => {
              const entry = e as Record<string, unknown>
              const msg = { ...(entry.message as Record<string, unknown>) }
              if (!msg.id && typeof entry.id === 'string') {
                msg.id = entry.id
              }
              return msg
            }) as unknown as AgentSession['messages']
          } catch {
            // getEntries failed — return empty messages
          }
        }
        send({
          channel: 'response',
          id: cmd.id,
          command: 'get_messages',
          success: true,
          data: { messages },
        })
        break
      }

      case 'get_fork_messages': {
        const messages = session.getUserMessagesForForking()
        send({
          channel: 'response',
          id: cmd.id,
          command: 'get_fork_messages',
          success: true,
          data: { messages },
        })
        break
      }

      case 'set_session_name': {
        session.setSessionName(cmd.name as string)
        send({ channel: 'response', id: cmd.id, command: 'set_session_name', success: true })
        break
      }

      case 'new_session': {
        const result = await runtime.newSession({
          parentSession: cmd.parentSession as string | undefined,
        })
        if (!result.cancelled) {
          session = runtime.session
          await bindSession()
        }
        send({ channel: 'response', id: cmd.id, command: 'new_session', success: true, data: result })
        break
      }

      case 'switch_session': {
        const result = await runtime.switchSession(cmd.sessionPath as string)
        if (!result.cancelled) {
          session = runtime.session
          await bindSession()
        }
        send({ channel: 'response', id: cmd.id, command: 'switch_session', success: true, data: result })
        break
      }

      case 'fork': {
        const result = await runtime.fork(cmd.entryId as string)
        if (!result.cancelled) {
          session = runtime.session
          await bindSession()
        }
        send({ channel: 'response', id: cmd.id, command: 'fork', success: true, data: { text: result.selectedText ?? '', cancelled: result.cancelled } })
        break
      }

      case 'compact': {
        const result = await session.compact(cmd.customInstructions as string | undefined)
        send({ channel: 'response', id: cmd.id, command: 'compact', success: true, data: result })
        break
      }

      case 'get_available_models': {
        const registry = session.modelRegistry
        const allModels = registry.getAll()
        const availableModels = registry.getAvailable()
        const availableIds = new Set(availableModels.map(m => `${m.provider}/${m.id}`))
        const models = allModels.map(m => ({
          provider: m.provider,
          id: m.id,
          name: m.name,
          hasAuth: availableIds.has(`${m.provider}/${m.id}`),
          reasoning: m.reasoning,
          contextWindow: m.contextWindow,
        }))
        send({ channel: 'response', id: cmd.id, command: 'get_available_models', success: true, data: { models } })
        break
      }

      case 'set_model': {
        const registry = session.modelRegistry
        const modelId = cmd.model as string
        const provider = cmd.provider as string | undefined
        let targetModel: typeof session.model | undefined
        if (provider) {
          targetModel = registry.find(provider, modelId)
        } else {
          const allModels = registry.getAll()
          targetModel = allModels.find(m => m.id === modelId) ?? allModels.find(m => m.name === modelId)
        }
        if (!targetModel) {
          send({ channel: 'response', id: cmd.id, command: 'set_model', success: false, error: `Model not found: ${provider ? provider + '/' : ''}${modelId}` })
          break
        }
        await session.setModel(targetModel)
        const newModel = session.model
        send({
          channel: 'response',
          id: cmd.id,
          command: 'set_model',
          success: true,
          data: newModel ? { provider: newModel.provider, id: newModel.id, name: newModel.name } : null,
        })
        break
      }

      case 'cycle_model': {
        const direction = (cmd.direction as 'forward' | 'backward' | undefined) ?? 'forward'
        const result = await session.cycleModel(direction)
        const newModel = session.model
        send({
          channel: 'response',
          id: cmd.id,
          command: 'cycle_model',
          success: true,
          data: {
            model: newModel ? { provider: newModel.provider, id: newModel.id, name: newModel.name } : null,
            thinkingLevel: session.thinkingLevel,
            isScoped: result?.isScoped ?? false,
          },
        })
        break
      }

      case 'set_thinking_level': {
        session.setThinkingLevel(cmd.level as string)
        send({ channel: 'response', id: cmd.id, command: 'set_thinking_level', success: true, data: { thinkingLevel: session.thinkingLevel } })
        break
      }

      case 'cycle_thinking_level': {
        const newLevel = session.cycleThinkingLevel()
        send({ channel: 'response', id: cmd.id, command: 'cycle_thinking_level', success: true, data: { thinkingLevel: newLevel } })
        break
      }

      case 'get_provider_auth_status': {
        const registry = runtime!.services.modelRegistry
        const allModels = registry.getAll()
        const providers = new Map<string, { configured: boolean; source?: string }>()
        for (const model of allModels) {
          if (!providers.has(model.provider)) {
            const status = registry.getProviderAuthStatus(model.provider)
            providers.set(model.provider, { configured: status.configured, source: status.source })
          }
        }
        const result: Record<string, { configured: boolean; source?: string }> = {}
        for (const [provider, status] of providers) {
          result[provider] = status
        }
        send({ channel: 'response', id: cmd.id, command: 'get_provider_auth_status', success: true, data: result })
        break
      }

      case 'set_api_key': {
        const authStorage = runtime!.services.authStorage
        authStorage.set(cmd.provider as string, { type: 'api_key', key: cmd.apiKey as string })
        runtime!.services.modelRegistry.refresh()
        send({ channel: 'response', id: cmd.id, command: 'set_api_key', success: true })
        break
      }

      case 'remove_auth': {
        const authStorage = runtime!.services.authStorage
        authStorage.remove(cmd.provider as string)
        runtime!.services.modelRegistry.refresh()
        send({ channel: 'response', id: cmd.id, command: 'remove_auth', success: true })
        break
      }

      case 'register_custom_provider': {
        const config = cmd.config as { name?: string; baseUrl: string; apiKey?: string; models?: Array<{ id: string; name: string; reasoning: boolean; input: string[]; cost: { input: number; output: number; cacheRead: number; cacheWrite: number }; contextWindow: number; maxTokens: number }> }
        runtime!.services.modelRegistry.registerProvider(cmd.provider as string, config)
        if (config.apiKey) {
          runtime!.services.authStorage.set(cmd.provider as string, { type: 'api_key', key: config.apiKey })
        }
        send({ channel: 'response', id: cmd.id, command: 'register_custom_provider', success: true })
        break
      }

      case 'send_extension_ui_response': {
        send({ channel: 'response', id: cmd.id, command: 'send_extension_ui_response', success: true })
        break
      }

      case 'flush_session': {
        // Force-write the session file to disk and mark flushed.
        // This mirrors what createBranchedSession does when it has assistant messages:
        //   this._rewriteFile(); this.flushed = true;
        // Without this, newSession() never writes the file (flushed=false),
        // so the sidebar can't see the new session until the first assistant response.
        if (sessionManager) {
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          ;(sessionManager as any)._rewriteFile()
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          ;(sessionManager as any).flushed = true
        }
        send({ channel: 'response', id: cmd.id, command: 'flush_session', success: true })
        break
      }

      default:
        send({ channel: 'response', id: cmd.id, command: cmd.type, success: false, error: `Unknown command: ${cmd.type}` })
    }
  } catch (err: unknown) {
    send({
      channel: 'response',
      id: cmd.id,
      command: cmd.type,
      success: false,
      error: err instanceof Error ? err.message : String(err),
    })
  }
}

process.parentPort.on('message', (event: Electron.ParentPortMessageEvent) => {
  const msg = event.data as WorkerCommand | { type: 'init'; data: WorkerInit }
  if (msg.type === 'init') {
    init((msg as { data: WorkerInit }).data).catch((err: Error) => {
      console.error('[PiWorker] Init failed:', err.message)
      console.error('[PiWorker] Stack:', err.stack)
      send({ channel: 'error', error: `Init failed: ${err.message}` })
    })
    return
  }

  handleCommand(msg as WorkerCommand).catch((err: Error) => {
    send({ channel: 'error', error: err.message })
  })
})

import { readdirSync, readFileSync, writeFileSync, existsSync, appendFileSync, unlinkSync, rmSync, mkdirSync } from 'fs'
import { join, dirname, resolve } from 'path'
import type {
  SessionInfo,
  SessionListResult,
  SessionFileHeader,
  ProjectSessionTree,
  SessionTreeNode,
  ForkPoint
} from '../renderer/src/types/session'

export function getSessionDir(cwd?: string): string {
  const projectRoot = cwd ?? process.cwd()
  const resolvedCwd = resolve(projectRoot)
  const agentDir = join(resolvedCwd, '.xi')
  const safePath = `--${resolvedCwd.replace(/^[/\\]/, '').replace(/[/\\:]/g, '-')}--`
  const sessionDir = join(agentDir, 'sessions', safePath)
  if (!existsSync(sessionDir)) {
    mkdirSync(sessionDir, { recursive: true })
  }
  return sessionDir
}


export function parseSessionFile(filePath: string): SessionInfo | null {
  try {
    const content = readFileSync(filePath, 'utf-8')
    const lines = content.split('\n').filter((line) => line.trim().length > 0)
    if (lines.length === 0) return null

    let header: SessionFileHeader
    try {
      header = JSON.parse(lines[0]) as SessionFileHeader
    } catch {
      return null
    }

    if (header.type !== 'session') return null

    let messageCount = 0
    let name: string | null = null
    let status: 'active' | 'completed' | null = null

    for (let i = 1; i < lines.length; i++) {
      try {
        const entry = JSON.parse(lines[i]) as Record<string, unknown>
        if (entry.type === 'message') {
          const message = entry.message as Record<string, unknown> | undefined
          if (message && message.role === 'user') {
            messageCount++
          }
        } else if (entry.type === 'session_info') {
          if (typeof entry.name === 'string') {
            name = entry.name
          }
          if (entry.status === 'active' || entry.status === 'completed') {
            status = entry.status
          }
        }
      } catch {
        continue
      }
    }

    return {
      filePath,
      sessionId: header.id,
      name,
      status,
      createdAt: header.timestamp,
      cwd: header.cwd,
      parentSessionPath: header.parentSession ?? null,
      messageCount,
      isMain: false
    }
  } catch {
    return null
  }
}

export function findMainSession(cwd: string, sessionDir?: string): SessionInfo | null {
  const dir = sessionDir ?? getSessionDir()
  if (!existsSync(dir)) return null

  const sessionFiles = readdirSync(dir)
    .filter((name) => name.endsWith('.jsonl'))
    .map((name) => join(dir, name))

  for (const filePath of sessionFiles) {
    const info = parseSessionFile(filePath)
    if (info && info.cwd === cwd && info.name === 'main') {
      return info
    }
  }

  const candidates: SessionInfo[] = []
  for (const filePath of sessionFiles) {
    const info = parseSessionFile(filePath)
    if (info && info.cwd === cwd) {
      candidates.push(info)
    }
  }
  if (candidates.length > 0) {
    candidates.sort((a, b) => a.createdAt.localeCompare(b.createdAt))
    return candidates[0]
  }

  return null
}

export function listSessions(_currentSessionPath?: string, sessionDir?: string): SessionListResult {
  const sessionDirPath = sessionDir ?? getSessionDir()
  if (!existsSync(sessionDirPath)) {
    return { projects: [] }
  }

  let sessionFiles: string[]
  try {
    sessionFiles = readdirSync(sessionDirPath)
      .filter((name) => name.endsWith('.jsonl'))
      .map((name) => join(sessionDirPath, name))
  } catch {
    return { projects: [] }
  }

  const sessions: SessionInfo[] = []
  for (const filePath of sessionFiles) {
    const info = parseSessionFile(filePath)
    if (info) sessions.push(info)
  }

  if (sessions.length === 0) {
    return { projects: [] }
  }

  sessions.sort((a, b) => a.createdAt.localeCompare(b.createdAt))

  const namedMain = sessions.find((s) => s.name === 'main')
  if (namedMain) {
    namedMain.isMain = true
  } else if (sessions.length > 0) {
    sessions[0].isMain = true
  }

  const cwd = sessions[0].cwd
  const tree = buildSessionTree(sessions)
  const encodedDir = sessionDirPath.split('/').pop() ?? ''

  const projects: ProjectSessionTree[] = [{
    projectPath: cwd,
    encodedDir,
    root: tree,
    allSessions: sessions
  }]

  return { projects }
}

export function buildSessionTree(sessions: SessionInfo[]): SessionTreeNode | null {
  if (sessions.length === 0) return null

  const nodeMap = new Map<string, SessionTreeNode>()
  const parentedNodes = new Set<string>()

  for (const session of sessions) {
    nodeMap.set(session.filePath, { session, children: [] })
  }

  for (const session of sessions) {
    if (session.parentSessionPath && nodeMap.has(session.parentSessionPath)) {
      const parent = nodeMap.get(session.parentSessionPath)!
      const node = nodeMap.get(session.filePath)!
      parent.children.push(node)
      parentedNodes.add(session.filePath)
    }
  }

  let root: SessionTreeNode | null = null

  const mainSession = sessions.find((s) => s.isMain)
  if (mainSession) {
    root = nodeMap.get(mainSession.filePath) ?? null
  }

  if (!root) {
    const orphan = sessions.find((s) => !parentedNodes.has(s.filePath))
    if (orphan) {
      root = nodeMap.get(orphan.filePath) ?? null
    }
  }

  if (!root && sessions.length > 0) {
    root = nodeMap.get(sessions[0].filePath) ?? null
  }

  if (root) {
    for (const session of sessions) {
      if (session.filePath === root.session.filePath) continue
      if (parentedNodes.has(session.filePath)) continue
      const node = nodeMap.get(session.filePath)!
      root.children.push(node)
    }
  }

  return root
}

export function nameSession(sessionPath: string, name: string, _cwd?: string, _parentSessionPath?: string): boolean {
  try {
    // Only append session_info if the file already exists on disk.
    // For new sessions, the Pi worker's flush_session command handles
    // creating the file with the correct header (including parentSession).
    // Creating the file here would break Pi's lazy-flush mechanism
    // (Pi uses openSync with 'wx' flag which fails if file exists).
    if (!existsSync(sessionPath)) {
      return true
    }

    const entry = JSON.stringify({
      type: 'session_info',
      name,
    })
    appendFileSync(sessionPath, entry + '\n')
    return true
  } catch {
    return false
  }
}

export function deleteSession(sessionPath: string, sessionDir?: string): boolean {
  if (!existsSync(sessionPath)) return false

  try {
    unlinkSync(sessionPath)

    const dir = dirname(sessionPath)
    const remaining = readdirSync(dir).filter((name) => name.endsWith('.jsonl'))
    if (remaining.length === 0) {
      rmSync(dir, { recursive: true })
    }

    return true
  } catch {
    return false
  }
}

export function addForkPoint(sessionPath: string, entryId: string, childName: string): boolean {
  if (!existsSync(sessionPath)) return false

  try {
    const entry = JSON.stringify({
